import React from'react';import{Outlet,useLocation}from'react-router-dom';import Sidebar from'../components/shared/Sidebar';import Header from'../components/shared/Header';
const M={'/admin':{t:'Dashboard',s:"Overview of your organisation"},'/admin/employees':{t:'Employees',s:'Manage your workforce'},'/admin/departments':{t:'Departments',s:'Manage teams'},'/admin/attendance':{t:'Attendance',s:'Mark and track attendance'},'/admin/payroll':{t:'Payroll',s:'Process salaries and slips'},'/admin/leaves':{t:'Leave Management',s:'Review leave requests'},'/admin/reports':{t:'Reports',s:'Analytics and summaries'}};
const css=`.layout{display:flex;min-height:100vh;}.lm{margin-left:var(--sw);flex:1;display:flex;flex-direction:column;min-height:100vh;min-width:0;}.lb{padding:28px;flex:1;}`;
export default function AdminLayout(){const{pathname}=useLocation();const m=M[pathname]||{t:'Admin',s:''};return(<><style>{css}</style><div className="layout"><Sidebar role="ADMIN"/><div className="lm"><Header title={m.t} subtitle={m.s}/><main className="lb"><Outlet/></main></div></div></>);}
